// Dentro de PanelCliente.js

useEffect(() => {
    const cargarDatosReales = async () => {
        try {
            // Reemplazamos la lógica de localStorage por la API
            const response = await fetch('http://localhost:5000/api/ofertas/todas'); // Necesitarás crear esta ruta en el backend
            const todasLasOfertas = await response.json();
            
            // Agrupamos las ofertas por local para mantener tu diseño de "filas por tienda"
            const agrupado = todasLasOfertas.reduce((acc, oferta) => {
                const nombreLocal = oferta.local.nombre;
                if (!acc[nombreLocal]) {
                    acc[nombreLocal] = { info: oferta.local, ofertas: [] };
                }
                acc[nombreLocal].ofertas.push(oferta);
                return acc;
            }, {});
            
            setOfertasPorLocal(agrupado);
        } catch (error) {
            console.error("Error cargando ofertas de la DB:", error);
        }
    };

    cargarDatosReales();
}, []);
